/**
 * Data Validator for HR Employee Records
 * Handles cleaning and validation of raw extracted data.
 */


    cleanName(name) {
        if (!name) return '';
        return name.trim().split(' ')
            .map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
            .join(' ');


    validateEmail(email) {
        const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
        return re.test(String(email).toLowerCase());


    validatePhone(phone) {
        // Basic international format check
        return /^\+?[1-9]\d{1,14 $/.test(phone.replace(/\s/g, ''));


    processValidation(rawData) {
        const errors = [];
        const cleaned = {
            firstName: cleanName(rawData.firstName),
            lastName: cleanName(rawData.lastName),
            email: rawData.email?.toLowerCase().trim(),
            phone: rawData.phone?.replace(/\s/g, ''),
            dob: rawData.dob, // Expected format YYYY-MM-DD
            taxId: rawData.taxId?.toUpperCase().trim(),
         ;

        if (!cleaned.firstName) errors.push('First name is required');
        if (!cleaned.lastName) errors.push('Last name is required');
        if (cleaned.email && !validateEmail(cleaned.email)) errors.push('Invalid email format');
        if (cleaned.phone && !validatePhone(cleaned.phone)) errors.push('Invalid phone format');
        if (!cleaned.taxId) errors.push('Tax ID is required');

        return {
            isValid: errors.length === 0,
            data: cleaned,
            errors: errors
         ;



// Main execution logic for this n8n node
const rawText = items[0].json.text;

// Logic to parse raw text into fields (regex-based for common forms)
const parsed = {
  firstName: rawText.match(/First Name:\s*(.*)/)?.[1],
  lastName: rawText.match(/Last Name:\s*(.*)/)?.[1],
  email: rawText.match(/Email:\s*(.*)/)?.[1],
  phone: items[0].json.phone,
  taxId: rawText.match(/Tax ID:\s*(.*)/)?.[1]
};

const result = processValidation(parsed);

if (result.isValid) {
  return [{
    json: {
      assignedId: 'NC-NEW-' + Math.floor(Math.random() * 1000),
      name: result.data.firstName + ' ' + result.data.lastName,
      contact1: result.data.phone,
      district: 'TBD',
      designation: 'Staff',
      cnic: result.data.taxId,
      gender: 'TBD',
      dob: result.data.dob || 'No record'
    }
  }];
} else {
  // For now, we throw an error. A better approach would be to route this to an error handling branch.
  throw new Error('Validation failed: ' + result.errors.join(', '));
}
